Bash(node -e "
const fs = require\('fs'\);
const html = fs.readFileSync\('games/neon-dash/index.html','utf8'\);
const m = html.match\(/<script>\\n?\\\(\\\(\\\) => \\{\([\\s\\S]*\)\\}\\\)\\\(\\\);\\n?<\\/script>/\);
if \(!m\) { console.log\('Could not extract script'\); process.exit\(1\); }
// Check for undefined variable references
const code = m[1];
// Look for any references to removed variables
const removed = ['highScore', 'LEVELS', 'currentLevel', 'levelProgress', 'levelLength', 'levelComplete', 'GAP_SIZE_ENDLESS'];
for \(const v of removed\) {
  const regex = new RegExp\('\\\\\\\\b' + v + '\\\\\\\\b'\);
  if \(regex.test\(code\)\) console.log\('Found reference to removed var:', v\);
}
console.log\('Check complete'\);
")
